// Entidad Customer con JPA y Lombok
package com.paymentchange.customer.entities;

import jakarta.persistence.*;
import lombok.Data;

@Data
@Entity
public class Customer {
    @Id
    @GeneratedValue(strategy = GenerationType.AUTO)
    private Long id;
    private String name;
    private String phoneNumber;
}

// Repository Interface
package com.paymentchange.customer.repositories;

import com.paymentchange.customer.entities.Customer;
import org.springframework.data.jpa.repository.JpaRepository;

public interface CustomerRepository extends JpaRepository<Customer, Long> {
    // Métodos heredados: save(), findAll(), findById(), delete()
    // No requiere implementación manual
}
